public class Solution { public List<List<int>> ThreeSum(int[] nums) { List<List<int>> result = new List<List<int>>(); Array.Sort(nums); int length = nums.Length; for (int i = 0; i < length - 2; i++) { if (i > 0 && nums[i] == nums[i - 1]) continue; if (nums[i] > 0) break; int current = nums[i]; int target = -current; int front = i + 1; int back = length - 1; while (front < back) { int diff = target - nums[front]; if (nums[back] > diff) { back--; continue; } if (nums[back] < diff) { front++; continue; } if (nums[front] + nums[back] == target) { result.Add(new List<int>() { current, nums[front], nums[back] }); front++; back--; while (front < back && nums[front] == nums[front - 1]) front++; while (front < back && nums[back] == nums[back + 1]) back--; continue; } } } return result; } }